code = """import json

# Read the package data from the file
with open("var_functions.query_db:2", "r") as f:
    package_data = json.load(f)

# Filter packages with MIT license and release versions
mit_release_packages = []
for pkg in package_data:
    # Check if MIT is in Licenses
    if "MIT" in pkg["Licenses"]:
        # Check VersionInfo for IsRelease: true
        version_info = pkg["VersionInfo"]
        if '"IsRelease": true' in version_info:
            mit_release_packages.append({
                "System": pkg["System"],
                "Name": pkg["Name"],
                "Version": pkg["Version"]
            })

print(f"Found {len(mit_release_packages)} MIT licensed release packages")
print("__RESULT__:")
print(json.dumps(mit_release_packages[:10]))  # Show first 10 as sample"""

